    private void givenPasswordParam(String id, boolean required, String defaultValue) {
        this.passwordParam = new GwtConfigParameter();
        this.passwordParam.setId(id);
        this.passwordParam.setName(id.substring(0, 1).toUpperCase() + id.substring(1));
        this.passwordParam.setType(GwtConfigParameterType.PASSWORD);
        this.passwordParam.setRequired(required);
        this.passwordParam.setCardinality(0);
        if (defaultValue != null) {
            this.passwordParam.setDefault(defaultValue);
        }
    }

    private void givenParamValue(String value) {
        this.passwordParam.setValue(value);
    }

    private void givenCurrentObjValue(Object value) {
        this.currentObjValue = value;
    }

    private void givenGwtConfigWithPasswordParam(String id, String name) {
        this.gwtConfig = new GwtConfigComponent();
        this.gwtConfig.setComponentId("test.pid");

        GwtConfigParameter param = new GwtConfigParameter();
        param.setId(id);
        param.setName(name);
        param.setType(GwtConfigParameterType.PASSWORD);
        param.setRequired(false);
        param.setCardinality(0);
        param.setValue(GwtServerUtil.PASSWORD_PLACEHOLDER);

        this.gwtConfig.setParameters(Arrays.asList(param));
    }

    private void givenCurrentCCWithPassword(String key, Password value) {
        Map<String, Object> props = new HashMap<>();
        props.put(key, value);
        this.currentCC = new ComponentConfigurationImpl("test.pid", null, props);
    }

    private void whenGetUserDefinedObjectIsCalled() {
        this.result = GwtServerUtil.getUserDefinedObject(this.passwordParam, this.currentObjValue);
    }

    private void whenFillPropertiesFromConfigurationIsCalled() {
        this.fillResult = GwtServerUtil.fillPropertiesFromConfiguration(this.gwtConfig, this.currentCC);
    }

    private void whenFillPropertiesFromConfigurationWithNullCCIsCalled() {
        this.fillResult = GwtServerUtil.fillPropertiesFromConfiguration(this.gwtConfig, null);
    }

    private void thenResultIsEmptyPassword() {
        assertNotNull("result must not be null", this.result);
        assertArrayEquals("password must be empty", new char[0], ((Password) this.result).getPassword());
    }

    private void thenResultIsPasswordWithValue(String expected) {
        assertNotNull("result must not be null", this.result);
        assertArrayEquals("password value mismatch", expected.toCharArray(), ((Password) this.result).getPassword());
    }

    private void thenFillResultPasswordIsEmpty(String key) {
        assertNotNull("fill result must not be null", this.fillResult);
        Object value = this.fillResult.get(key);
        assertNotNull("password entry must be present", value);
        assertArrayEquals("password must be empty", new char[0], ((Password) value).getPassword());
    }

    private void thenFillResultPasswordHasValue(String key, String expected) {
        assertNotNull("fill result must not be null", this.fillResult);
        Object value = this.fillResult.get(key);
        assertNotNull("password entry must be present", value);
        assertArrayEquals("password value mismatch", expected.toCharArray(), ((Password) value).getPassword());
    }

